enum Sign { SIGN_NEGATIVE = -1, SIGN_ZERO = 0, SIGN_POSITIVE = 1 };

int classify_zone(double x) {
    Sign s;
    if (x < 0.0) s = SIGN_NEGATIVE;
    else if (x == 0.0) s = SIGN_ZERO;
    else s = SIGN_POSITIVE;

    switch (s) {
        case SIGN_NEGATIVE:
            if (x < -100.0) return -2;
            return -1;
        case SIGN_ZERO:
            return 0;
        case SIGN_POSITIVE:
        default:
            if (x > 100.0) return 2;
            return 1;
    }
}

