enum State { STATE_IDLE, STATE_RUNNING, STATE_PAUSED, STATE_STOPPED };
enum Event { EV_START, EV_PAUSE, EV_RESUME, EV_STOP };

int next_state(int state, int event) {
    switch (state) {
        case STATE_IDLE:
            if (event == EV_START) return STATE_RUNNING;
            return STATE_IDLE;
        case STATE_RUNNING:
            if (event == EV_PAUSE) return STATE_PAUSED;
            if (event == EV_STOP) return STATE_STOPPED;
            return STATE_RUNNING;
        case STATE_PAUSED:
            if (event == EV_RESUME) return STATE_RUNNING;
            if (event == EV_STOP) return STATE_STOPPED;
            return STATE_PAUSED;
        default:
            return STATE_STOPPED;
    }
}

