def next_state(state: Int, event: Int) -> Int:
    if state == STATE_IDLE:
        if event == EV_START:
            return STATE_RUNNING
        return STATE_IDLE
    elif state == STATE_RUNNING:
        if event == EV_PAUSE:
            return STATE_PAUSED
        elif event == EV_STOP:
            return STATE_STOPPED
        return STATE_RUNNING
    elif state == STATE_PAUSED:
        if event == EV_RESUME:
            return STATE_RUNNING
        elif event == EV_STOP:
            return STATE_STOPPED
        return STATE_PAUSED
    else:
        return STATE_STOPPED

